#include <bits/stdc++.h>
using namespace std;

int par[1000001];
int find(int x){ return par[x]==x?x:par[x]=find(par[x]); }

int main() {
    ios_base::sync_with_stdio(false); cin.tie(NULL);
    int n, m; cin >> n >> m;
    for(int i=1;i<=n;i++) par[i]=i;
    string out;
    while(m--){
        int op,a,b; cin >> op >> a >> b;
        if(op==0){
            int ra=find(a), rb=find(b);
            if(ra!=rb) par[ra]=rb;
        } else {
            if(find(a)==find(b)) out += "YES\n"; else out += "NO\n";
        }
    }
    cout << out;
    return 0;
}
